mapper.update:
UPDATE TERMS
SET status     = #{status},
    updated_at = SYSTIMESTAMP

    , approved_by = #{changedBy}
    , approved_at = SYSTIMESTAMP

WHERE terms_id = #{termsId}

mapper.select:
SELECT t.terms_id, t.terms_master_id, t.version, t.status, t.required_yn, t.reconsent_required_yn, t.effective_from, t.effective_to, t.created_at, tm.title, tm.terms_type FROM TERMS t INNER JOIN TERMS_MASTERS tm ON t.terms_master_id = tm.terms_master_id
t.status = #{status}
ORDER BY t.created_at DESC
